import { Metadata } from '@metaplex-foundation/mpl-token-metadata';
import { utils } from '@coral-xyz/anchor';
import { MintLayout, MintInfo, TOKEN_PROGRAM_ID } from '@solana/spl-token';
import { Connection, PublicKey } from '@solana/web3.js';

const TOKEN_METADATA_PROGRAM_ID = new PublicKey('metaqbxxUerdq28cj1RbAWkYQm3ybzjb6a8bt518x1s');

// This is not an official program but a community deployement
const TOKEN_2022_METADATA_PROGRAM_ID = new PublicKey('META4s4fSmpkTbZoUsgC1oBnWB31vQcmnN8giPw51Zu');

export function findMetadataAddress(mint: PublicKey, tokenProgramId: PublicKey): PublicKey {
  const metadataProgramId = tokenProgramId.equals(TOKEN_PROGRAM_ID)
    ? TOKEN_METADATA_PROGRAM_ID
    : TOKEN_2022_METADATA_PROGRAM_ID;

  return PublicKey.findProgramAddressSync(
    [Buffer.from('metadata'), metadataProgramId.toBuffer(), mint.toBuffer()],
    metadataProgramId,
  )[0];
}

type TokenMetadata = {
  publicKey: PublicKey;
  account: Metadata;
};

type TokenMintWithProgramId = {
  mint: PublicKey;
  programId: PublicKey;
};

interface RawMintWithProgramId extends MintInfo {
  programId: PublicKey;
}

export async function fetchMintInfos(
  connection: Connection,
  mints: PublicKey[],
): Promise<Array<[string, RawMintWithProgramId]>> {
  const results = (await utils.rpc.getMultipleAccounts(connection, mints)).reduce((acc, m, idx) => {
    if (m) {
      acc.push([
        mints[idx].toString(),
        {
          ...MintLayout.decode(m.account.data),
          programId: m.account.owner,
        },
      ]);
    }
    return acc;
  }, new Array<[string, RawMintWithProgramId]>());

  return results;
}

export const removeEmptyChars = (value: string) => value.replace(/\u0000/g, '');

export async function fetchTokenMetadatas(
  connection: Connection,
  tokens: TokenMintWithProgramId[],
): Promise<TokenMetadata[]> {
  const metadataAddresses = tokens.map((t) => findMetadataAddress(t.mint, t.programId));

  const tokenMetaAccounts = (await utils.rpc.getMultipleAccounts(connection, metadataAddresses)).reduce(
    (acc, keyedAccount) => {
      if (keyedAccount) {
        const metadata = Metadata.deserialize(keyedAccount.account.data)[0];
        metadata.data.name = removeEmptyChars(metadata.data.name);
        metadata.data.symbol = removeEmptyChars(metadata.data.symbol);
        metadata.data.uri = removeEmptyChars(metadata.data.uri);

        acc.push({
          publicKey: keyedAccount.publicKey,
          account: metadata,
        });
      }
      return acc;
    },
    new Array<TokenMetadata>(),
  );

  return tokenMetaAccounts;
}
